arguments.command:
$headers = @{ apikey=$env:SUPABASE_SERVICE_ROLE_KEY; Authorization="Bearer $($env:SUPABASE_SERVICE_ROLE_KEY)" }
$url = "$($env:SUPABASE_URL)/rest/v1/agent_metrics?select=agent_id,last_heartbeat_at,error_rate,response_time_ms,memory_utilization,updated_at,division,is_division_head&order=agent_id.asc"
try { $res = Invoke-RestMethod -Uri $url -Headers $headers -Method Get; $res | ConvertTo-Json -Depth 5 } catch { $_ | Out-String }

$headers = @{ apikey=$env:SUPABASE_ANON_KEY; Authorization="Bearer $($env:SUPABASE_ANON_KEY)" }
$url = "$($env:SUPABASE_URL)/rest/v1/agent_metrics?select=*&limit=5"
try { $res = Invoke-RestMethod -Uri $url -Headers $headers -Method Get; $res | ConvertTo-Json -Depth 6 } catch { $_ | Out-String }

$headers = @{ apikey=$env:SUPABASE_ANON_KEY; Authorization="Bearer $($env:SUPABASE_ANON_KEY)" }
$url = "$($env:SUPABASE_URL)/rest/v1/"
try { $r = Invoke-WebRequest -Uri $url -Headers $headers -Method Get; Write-Output "Status:$($r.StatusCode)"; Write-Output $r.Content } catch { Write-Output $_.Exception.Message; if ($_.Exception.Response){$sr = New-Object IO.StreamReader($_.Exception.Response.GetResponseStream()); $sr.ReadToEnd() | Write-Output } }

$ProgressPreference='SilentlyContinue'; $headers = @{ apikey=$env:SUPABASE_ANON_KEY; Authorization="Bearer $($env:SUPABASE_ANON_KEY)" }
$url = "$($env:SUPABASE_URL)/rest/v1/agent_metrics?select=*&limit=3"
try { $r = Invoke-WebRequest -UseBasicParsing -Uri $url -Headers $headers -Method Get; Write-Output "Status:$($r.StatusCode)"; Write-Output $r.Content } catch { Write-Output $_.Exception.Message; if ($_.Exception.Response){$sr = New-Object IO.StreamReader($_.Exception.Response.GetResponseStream()); $sr.ReadToEnd() | Write-Output } }

$ProgressPreference='SilentlyContinue'; $headers = @{ apikey=$env:SUPABASE_SERVICE_ROLE_KEY }
$url = "$($env:SUPABASE_URL)/rest/v1/agent_metrics?select=*&limit=3"
try { $r = Invoke-WebRequest -UseBasicParsing -Uri $url -Headers $headers -Method Get; "Status:$($r.StatusCode)"; $r.Content } catch { $_.Exception.Message; if ($_.Exception.Response){$sr = New-Object IO.StreamReader($_.Exception.Response.GetResponseStream()); $sr.ReadToEnd() } }

